import React, { useState } from "react";

function Alert({ type = "info", children, dismissible = false }) {
  const [visible, setVisible] = useState(true);

  if (!visible) return null;

  const iconMap = {
    info: "ℹ️",
    success: "✅",
    error: "❌",
  };

  return (
    <div className={`alert ${type}`}>
      <span style={{ marginRight: "10px", fontSize: "1.2em" }}>{iconMap[type] || "ℹ️"}</span>
      <div style={{ flex: 1 }}>{children}</div>
      {dismissible && (
        <button
          onClick={() => setVisible(false)}
          style={{
            background: "none",
            border: "none",
            color: "inherit",
            cursor: "pointer",
            fontSize: "1.2em",
            opacity: 0.7,
          }}
        >
          ✖
        </button>
      )}
    </div>
  );
}

export default Alert;
